INSERT INTO ""Events"" (""Title"", ""Description"", ""Price"", ""IdOrganisation"", ""StartDate"", ""EndDate"", ""CityId"") VALUES
(E'Марафон «Разом до перемоги»', E'Щорічний благодійний марафон для ветеранів та волонтерів. Дистанції: 5 км, 10 км, 21 км. Усі учасники отримують медаль фінішера. Кошти від реєстрації спрямовуються на реабілітацію поранених.', 3, 1, '2026-06-07 06:00:00+00', '2026-06-07 11:00:00+00', 1),
(E'Група психологічної підтримки «Свої»', 'Щотижнева закрита група для ветеранів, які переживають наслідки бойового стресу. Веде сертифікований психолог із досвідом роботи з ПТСР. Участь анонімна та безкоштовна.', 0, 1, '2026-06-03 14:00:00+00', '2026-06-03 16:00:00+00', 1),
(E'Майстер-клас із живопису «Фарби миру»', E'Творча зустріч для ветеранів і членів їхніх родин. Художник Олег Ткач навчить технік акрилового живопису. Усі матеріали включено. Кількість місць обмежена — 15 осіб.', 3, 1, '2026-06-14 08:00:00+00', '2026-06-14 11:00:00+00', 1),
(E'Рибальський турнір «Річка рятує»', E'Дводенний рибальський фестиваль на березі Десни. Конкурс на найбільший улов, майстер-класи від досвідчених рибалок, вечірній багаттяний концерт. Проживання та харчування включено.', 3, 1, '2026-07-05 04:00:00+00', '2026-07-06 15:00:00+00', 1),
(E'Зустріч ветеранського ком''юніті «Свої серед своїх»', 'Щомісячна неформальна зустріч ветеранів та ветеранок у затишній локації. Спільна вечеря, обмін досвідом, знайомства. Запрошуємо всіх, хто шукає спільноту.', 0, 1, '2026-06-20 15:30:00+00', '2026-06-20 18:30:00+00', 1),
(E'Семінар «Юридичні права ветерана»', E'Практичний семінар із юристами фонду. Теми: соціальні гарантії, пільги, оформлення інвалідності, земельні питання. Безкоштовна індивідуальна консультація після семінару.', 0, 1, '2026-06-10 07:00:00+00', '2026-06-10 10:00:00+00', 1),
('Адаптивне плавання: старт сезону', E'Відкрите тренування з адаптивного плавання у басейні «Авангард». Інструктор-паралімпієць Андрій Мельник проведе заняття для ветеранів із різними рівнями фізичних можливостей. Інвентар надається.', 3, 2, '2026-06-01 07:00:00+00', '2026-06-01 09:00:00+00', 1),
(E'Йога для ветеранів «Тіло і спокій»', E'Щотижневий клас хатха-йоги, адаптований для людей із травмами та обмеженою рухливістю. Викладач — сертифікований йога-терапевт. Заняття проходять у просторому залі з матами та підпорками.', 3, 2, '2026-06-04 06:00:00+00', '2026-06-04 07:30:00+00', 1),
(E'Освітній інтенсив «Нова кар''єра після служби»', E'Дводенний тренінг від HR-партнерів Хабу. Теми: складання резюме для ветерана, підготовка до співбесіди, перекваліфікація в IT та інші галузі. Учасники отримують сертифікат.', 3, 2, '2026-06-19 06:00:00+00', '2026-06-20 14:00:00+00', 1),
(E'Похід Карпатами «Наш Захід»', E'П''ятиденний похід для ветеранів маршрутом Яремче–Говерла–Буковель. Досвідчені гіди, спорядження, харчування та транспорт включено. Маршрут розрахований на середній рівень підготовки.', 3, 2, '2026-07-21 05:00:00+00', '2026-07-25 17:00:00+00', 2),
(E'Музичний вечір «Струни душі»', E'Акустичний концерт за участю ветеранів-музикантів і запрошених артистів. Жанри: рок, фолк, блюз. Вхід вільний, є бар із безалкогольними напоями та чаєм.', 0, 2, '2026-06-27 16:00:00+00', '2026-06-27 19:00:00+00', 1),
(E'Групова психотерапія «Шлях до себе»', E'Терапевтична група на основі КПТ (когнітивно-поведінкової терапії). Курс із 8 занять двічі на тиждень. Ведуть два психотерапевти. Реєстрація обов''язкова — місця обмежені.', 3, 2, '2026-06-09 13:00:00+00', '2026-07-28 14:30:00+00', 1),
(E'Велозабіг «Ветеранська верства»', E'Сімейний велозабіг у Гідропарку для ветеранів та їхніх близьких. Дистанції 10 і 20 км. Пункти харчування на маршруті, фінішна фотозона та концерт для учасників.', 3, 2, '2026-06-28 07:00:00+00', '2026-06-28 11:00:00+00', 1),
(E'Паралімпійські змагання «Сила духу»', E'Відкриті змагання з адаптивних видів спорту: настільний теніс, стрільба з лука, плавання, важка атлетика. Учасники змагаються у своїх категоріях. Нагородження медалями та подарунками.', 3, 3, '2026-06-13 07:00:00+00', '2026-06-13 14:00:00+00', 2),
(E'День волонтера «Долучись до добра»', E'Спільний день прибирання та впорядкування ветеранського парку у Львові. Після роботи — пікнік і неформальне спілкування. Запрошуються ветерани, члени родин і всі охочі.', 0, 3, '2026-06-08 06:00:00+00', '2026-06-08 12:00:00+00', 2),
